const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let pos = 0;
const T = Number(input[pos++]);
if (T < 1 || T > 5) process.exit(0);
let res = [];
for(let i=0;i<T;i++){
  const p = Number(input[pos++]);
  if(p<1 || p>4096) process.exit(0);
  let x = p, cnt = 0;
  while(x){ x &= x-1; cnt++; }
  res.push(String(cnt));
}
